"""Loguru routing and stdout redirection for parallel workers.

This module handles:
- Stripping loguru from function globals for pickling
- Re-injecting loguru in worker processes
- Redirecting stdout to loguru so print() appears above progress bars
- Forwarding log messages from workers to main process via queue
"""
from __future__ import annotations

import contextlib
import sys
import threading
from dataclasses import dataclass
from typing import Any, Callable


@dataclass
class LoguruConfig:
    """Configuration for loguru in worker processes."""
    stripped_names: set[str]
    log_queue: Any  # multiprocessing.Queue


class LoguruStdoutRedirector:
    """Redirects stdout writes to loguru so they appear above progress bar."""
    def __init__(self):
        self._buffer = ""

    def write(self, msg: str) -> None:
        if not msg:
            return
        self._buffer += msg
        while "\n" in self._buffer:
            line, self._buffer = self._buffer.split("\n", 1)
            if line.strip():
                try:
                    from loguru import logger
                    logger.opt(depth=2).info(line.rstrip())
                except Exception:
                    pass

    def flush(self) -> None:
        if self._buffer.strip():
            try:
                from loguru import logger
                logger.opt(depth=2).info(self._buffer.rstrip())
            except Exception:
                pass
            self._buffer = ""


def create_queue_sink(log_queue):
    """Create a loguru sink that writes to a multiprocessing queue."""
    def sink(message):
        try:
            log_queue.put_nowait(str(message).rstrip())
        except Exception:
            pass
    return sink


def start_log_consumer(log_queue, live):
    """Start a thread that consumes log messages and prints above progress bar."""
    import queue as queue_module

    stop_event = threading.Event()

    def consumer():
        while not stop_event.is_set():
            try:
                message = log_queue.get(timeout=0.1)
                if message and live:
                    live.console.print(message)
            except queue_module.Empty:
                continue
        while True:
            try:
                message = log_queue.get_nowait()
                if message and live:
                    live.console.print(message)
            except queue_module.Empty:
                break

    thread = threading.Thread(target=consumer, daemon=True)
    thread.start()
    return stop_event, thread


def find_loguru_names(f: Callable) -> set[str]:
    """Find loguru Logger names in function globals without mutating."""
    names: set[str] = set()
    try:
        from loguru._logger import Logger
        if hasattr(f, '__globals__'):
            for name, value in f.__globals__.items():
                if isinstance(value, Logger):
                    names.add(name)
    except ImportError:
        pass
    return names


def strip_loguru_from_globals(f: Callable, names: set[str]) -> None:
    """Remove loguru Logger from function globals to allow pickling."""
    if not names or not hasattr(f, '__globals__'):
        return
    for name in names:
        if name in f.__globals__:
            f.__globals__[name] = None


def setup_worker_loguru(config: LoguruConfig) -> None:
    """Configure loguru in worker process."""
    if config.log_queue is None:
        return
    try:
        from loguru import logger
        logger.remove()
        logger.add(
            create_queue_sink(config.log_queue),
            format="{time:HH:mm:ss} | {level: <8} | {message}",
            colorize=False
        )
    except ImportError:
        pass


def reinject_loguru(f: Callable, stripped_names: set[str]) -> None:
    """Re-inject loguru into function globals after pickle."""
    if not stripped_names or not hasattr(f, '__globals__'):
        return
    try:
        from loguru import logger
        for name in stripped_names:
            if f.__globals__.get(name) is None:
                f.__globals__[name] = logger
    except ImportError:
        pass


def make_worker_wrapper(f: Callable, config: LoguruConfig) -> Callable:
    """Create wrapper that routes all output through loguru."""
    def wrapper(*args, **kwargs):
        setup_worker_loguru(config)
        reinject_loguru(f, config.stripped_names)

        old_stdout = sys.stdout
        sys.stdout = LoguruStdoutRedirector()
        try:
            return f(*args, **kwargs)
        finally:
            sys.stdout.flush()
            sys.stdout = old_stdout
    return wrapper


@contextlib.contextmanager
def redirect_loguru_to_live(live):
    """Redirect loguru output to print above the Rich Live display."""
    if live is None:
        yield
        return

    try:
        import loguru
        loguru.logger.remove()
        handler_id = loguru.logger.add(
            lambda m: live.console.print(m, end=""),
            colorize=True,
            format="{time:HH:mm:ss} | {level: <8} | {message}"
        )
        try:
            yield
        finally:
            loguru.logger.remove(handler_id)
            loguru.logger.add(sys.stderr)
    except ImportError:
        yield


@contextlib.contextmanager
def log_consumer(log_queue: Any, live: Any):
    """Context manager for log consumer thread lifecycle."""
    if log_queue is None or live is None:
        yield
        return

    stop_event, thread = start_log_consumer(log_queue, live)
    try:
        yield
    finally:
        stop_event.set()
        thread.join(timeout=1.0)

"""Unified tqdm-based progress bars - single implementation for terminal and notebook."""
from __future__ import annotations

import contextlib
import multiprocessing
import re
import sys
import threading
from dataclasses import dataclass
from typing import Any, Callable
import queue as queue_module

import joblib
from joblib import Parallel, delayed
from tqdm.auto import tqdm

# ANSI escape code pattern
ANSI_ESCAPE = re.compile(r'\x1B(?:[@-Z\\-_]|\[[0-?]*[ -/]*[@-~])')


from .. import is_notebook


def strip_ansi(text: str) -> str:
    """Remove ANSI escape codes from text."""
    return ANSI_ESCAPE.sub('', text)


class AnsiStrippingStdoutProxy:
    """Stdout proxy that strips ANSI escape codes before writing.

    Used in notebook thread/sequential modes where print() and rich.print()
    write directly to stdout with ANSI codes that render as garbage in Jupyter.
    """
    def __init__(self, real_stdout):
        self._real = real_stdout

    def write(self, msg: str) -> int:
        return self._real.write(strip_ansi(msg))

    def flush(self) -> None:
        self._real.flush()

    def __getattr__(self, name):
        return getattr(self._real, name)


@contextlib.contextmanager
def notebook_stdout_filter():
    """Strip ANSI from stdout in notebook environments. No-op in terminals."""
    if not is_notebook():
        yield
        return
    old_stdout = sys.stdout
    sys.stdout = AnsiStrippingStdoutProxy(old_stdout)
    try:
        yield
    finally:
        sys.stdout = old_stdout


def safe_write(pbar, message: str) -> None:
    """Write message compatible with both terminal and notebook."""
    if is_notebook():
        # In notebook: use print() - logs appear above, widget stays at bottom
        print(strip_ansi(message))
    else:
        # In terminal: use tqdm.write() for proper cursor handling
        pbar.write(message)

from ..loguru_routing import (
    LoguruConfig,
    find_loguru_names,
    strip_loguru_from_globals,
    make_worker_wrapper,
)


@dataclass
class ParallelMode:
    """Configuration for parallel execution."""
    using_threads: bool
    log_queue: Any  # multiprocessing.Queue | None
    wrapped_func: Callable
    stripped_names: set[str]
    manager: Any = None  # multiprocessing.Manager | None


def prepare_parallel_mode(f: Callable, prefer: str | None) -> ParallelMode:
    """Prepare function for parallel execution."""
    using_threads = prefer == 'threads'

    if using_threads:
        return ParallelMode(
            using_threads=True,
            log_queue=None,
            wrapped_func=f,
            stripped_names=set(),
        )

    # Process mode: need Manager for pickleable queue
    stripped_names = find_loguru_names(f)
    strip_loguru_from_globals(f, stripped_names)
    manager = multiprocessing.Manager()
    log_queue = manager.Queue()
    config = LoguruConfig(stripped_names, log_queue)

    return ParallelMode(
        using_threads=False,
        log_queue=log_queue,
        wrapped_func=make_worker_wrapper(f, config),
        stripped_names=stripped_names,
        manager=manager,
    )


def sequential_map(f: Callable, arr: list, desc: str, disable: bool) -> list:
    """Sequential map with tqdm progress bar."""
    if disable:
        return [f(item) for item in arr]

    results = []
    with notebook_stdout_filter(), redirect_loguru_to_tqdm() as pbar_ref:
        pbar = tqdm(arr, desc=desc)
        pbar_ref[0] = pbar
        for item in pbar:
            results.append(f(item))
    return results


@contextlib.contextmanager
def redirect_loguru_to_tqdm():
    """Redirect loguru output to tqdm.write()."""
    pbar_ref = [None]  # Mutable reference for pbar
    in_notebook = is_notebook()

    def write_fn(m):
        msg = str(m).rstrip()
        if pbar_ref[0] is not None:
            safe_write(pbar_ref[0], msg)
        else:
            print(strip_ansi(msg) if in_notebook else msg)

    try:
        import loguru
        loguru.logger.remove()
        handler_id = loguru.logger.add(
            write_fn,
            colorize=not in_notebook,  # No colors in notebook
            format="{time:HH:mm:ss} | {level: <8} | {message}"
        )
        try:
            yield pbar_ref
        finally:
            loguru.logger.remove(handler_id)
            loguru.logger.add(sys.stderr)
    except ImportError:
        yield pbar_ref


@contextlib.contextmanager
def log_consumer_tqdm(log_queue: Any, pbar):
    """Consume log messages from queue and write via tqdm."""
    if log_queue is None:
        yield
        return

    stop_event = threading.Event()

    def consumer():
        while not stop_event.is_set():
            try:
                message = log_queue.get(timeout=0.1)
                if message and pbar:
                    safe_write(pbar, message)
            except queue_module.Empty:
                continue
        # Drain remaining
        while True:
            try:
                message = log_queue.get_nowait()
                if message and pbar:
                    safe_write(pbar, message)
            except queue_module.Empty:
                break

    thread = threading.Thread(target=consumer, daemon=True)
    thread.start()
    try:
        yield
    finally:
        stop_event.set()
        thread.join(timeout=1.0)


def run_with_simple_bar(mode: ParallelMode, arr: list, n_jobs: int, batch_size,
                        disable_tqdm: bool, desc: str, kwargs: dict) -> list:
    """Run with single tqdm progress bar."""
    pbar = tqdm(total=len(arr), desc=desc, disable=disable_tqdm)

    class TqdmCallback(joblib.parallel.BatchCompletionCallBack):
        def __call__(self, out):
            pbar.update(n=self.batch_size)
            return super().__call__(out)

    old_cb = joblib.parallel.BatchCompletionCallBack
    joblib.parallel.BatchCompletionCallBack = TqdmCallback

    try:
        with log_consumer_tqdm(mode.log_queue, pbar):
            if mode.using_threads:
                with notebook_stdout_filter(), redirect_loguru_to_tqdm() as pbar_ref:
                    pbar_ref[0] = pbar
                    results = Parallel(n_jobs=n_jobs, batch_size=batch_size, **kwargs)(
                        delayed(mode.wrapped_func)(i) for i in arr
                    )
            else:
                results = Parallel(n_jobs=n_jobs, batch_size=batch_size, **kwargs)(
                    delayed(mode.wrapped_func)(i) for i in arr
                )
    finally:
        joblib.parallel.BatchCompletionCallBack = old_cb
        pbar.close()

    return results


def run_with_job_bars(mode: ParallelMode, arr: list, n_jobs: int, batch_size,
                      disable_tqdm: bool, desc: str, total_tasks: int,
                      total_cpus: int, kwargs: dict) -> list:
    """Run with per-job tqdm progress bars."""
    # In notebooks, multi-position bars don't work well - use simple bar
    if is_notebook():
        return run_with_simple_bar(mode, arr, n_jobs, batch_size,
                                   disable_tqdm, desc, kwargs)

    # Overall progress bar at position 0
    overall = tqdm(total=total_tasks, desc=f"{desc}", position=0,
                   disable=disable_tqdm, leave=True)

    # Track active job bars
    active_bars = {}
    bar_lock = threading.Lock()
    job_counter = [0]

    class TqdmJobCallback(joblib.parallel.BatchCompletionCallBack):
        def __call__(self, out):
            with bar_lock:
                overall.update(n=self.batch_size)
                job_counter[0] += 1
                job_num = job_counter[0]

                # Clean up old bars (keep max total_cpus active)
                while len(active_bars) >= total_cpus:
                    oldest = min(active_bars.keys())
                    active_bars[oldest].close()
                    del active_bars[oldest]

                # Add new bar showing job completion
                pos = (len(active_bars) % total_cpus) + 1
                bar = tqdm(total=1, desc=f"  Job {job_num:>4}", position=pos,
                          leave=False, disable=disable_tqdm,
                          bar_format='{desc}: {bar} | {elapsed}')
                bar.update(1)
                active_bars[job_num] = bar

            return super().__call__(out)

    old_cb = joblib.parallel.BatchCompletionCallBack
    joblib.parallel.BatchCompletionCallBack = TqdmJobCallback

    try:
        with log_consumer_tqdm(mode.log_queue, overall):
            if mode.using_threads:
                with notebook_stdout_filter(), redirect_loguru_to_tqdm() as pbar_ref:
                    pbar_ref[0] = overall
                    results = Parallel(n_jobs=n_jobs, batch_size=batch_size, **kwargs)(
                        delayed(mode.wrapped_func)(i) for i in arr
                    )
            else:
                results = Parallel(n_jobs=n_jobs, batch_size=batch_size, **kwargs)(
                    delayed(mode.wrapped_func)(i) for i in arr
                )
    finally:
        joblib.parallel.BatchCompletionCallBack = old_cb
        with bar_lock:
            for bar in active_bars.values():
                bar.close()
        overall.close()
        # Clear the extra lines from job bars
        print('\n' * total_cpus, end='')

    return results

